func main() {
    set := map[string]bool{"apple": true, "banana": true}

    // Add
    set["cherry"] = true

    // Check membership
    fmt.Println(set["apple"])    // true
    fmt.Println(set["grape"])    // false

    // Size
    fmt.Println(len(set))        // 3
}

