func main() {
    a := map[int]bool{1: true, 2: true, 3: true}
    b := map[int]bool{2: true, 3: true, 4: true}

    // Intersection
    inter := map[int]bool{}
    for k := range a {
        if b[k] {
            inter[k] = true
        }
    }
    fmt.Println(inter)  // map[2:true 3:true]
}

