func main() {
    graph := map[int][]int{1: {2, 3}, 2: {4}, 3: {4}, 4: {}}
    visited := map[int]bool{}
    queue := []int{1}
    visited[1] = true

    for len(queue) > 0 {
        node := queue[0]
        queue = queue[1:]
        fmt.Println(node)
        for _, neighbor := range graph[node] {
            if !visited[neighbor] {
                visited[neighbor] = true
                queue = append(queue, neighbor)
            }
        }
    }
}

